// ============================================================
// 断路器数据验证与转换 (V4.2 - 修复 sim_fault tag 导致双线问题)
// ============================================================

const payload = msg.payload;

// 1. 提取设备 ID (优先从 Topic 提取: pv/device_001/data)
const topic_parts = (msg.topic || "").split('/');
let device_id = (topic_parts.length >= 2) ? topic_parts[1] : (payload.device_id || 'unknown');

// 2. 基本格式校验
if (!payload || typeof payload !== 'object') {
    node.error("Invalid payload format", msg);
    return null;
}

// 3. 必需字段检查
const required_fields = ['voltage', 'current', 'power', 'status', 'temperature'];
for (let field of required_fields) {
    if (payload[field] === undefined) {
        node.warn(`Missing required field: ${field}`);
        return null;
    }
}

// 4. 时间戳处理 (Unix秒 -> JS Date)
let ts;
const rawTs = Number(payload.timestamp);
if (!isNaN(rawTs) && rawTs > 0) {
    ts = new Date(rawTs < 10000000000 ? rawTs * 1000 : rawTs);
} else {
    ts = new Date();
}

// ============================================================
// 5. 核心：标准数组格式 [fields, tags]
//    注意：tags 只保留 device_id，不放 sim_fault
//    sim 相关字段全部放 fields，避免产生多条时间序列
// ============================================================

const fields = {
    // 基础电气参数（真实 + 模拟都有）
    voltage: parseFloat(Number(payload.voltage).toFixed(2)),
    current: parseFloat(Number(payload.current).toFixed(3)),
    power: parseFloat(Number(payload.power).toFixed(2)),
    efficiency: parseFloat(Number(payload.efficiency || 0.5).toFixed(2)),
    temperature: parseFloat(Number(payload.temperature).toFixed(2)),
    status: (payload.status === true || payload.status === 1) ? 1.0 : 0.0
};

// 模拟器专属字段（真实设备没有，不会写入）
if (payload.sim_ghi !== undefined) fields.sim_ghi = parseFloat(payload.sim_ghi);
if (payload.sim_k !== undefined) fields.sim_k = parseFloat(payload.sim_k);
if (payload.sim_pr !== undefined) fields.sim_pr = parseFloat(payload.sim_pr);

// sim_fault 用数字编码放进 fields（不放 tags！）
if (payload.sim_fault !== undefined) {
    const fault_code = { 'severe': 3, 'degraded': 2, 'normal': 0 };
    fields.sim_fault_code = fault_code[payload.sim_fault] || 0;
}

// 地理坐标
if (payload.latitude !== undefined) fields.latitude = parseFloat(payload.latitude);
if (payload.longitude !== undefined) fields.longitude = parseFloat(payload.longitude);

// tags: device_id + region（从注册表读）
const registry = global.get('device_registry') || {};
const deviceInfo = registry[String(device_id)];

const tags = {
    device_id: String(device_id),
    region: (deviceInfo && deviceInfo.location) ? deviceInfo.location.toLowerCase() : "unknown"
};
msg.payload = [fields, tags];

// ============================================================

// 6. 传递原始数据供下游节点使用
msg.device_id = device_id;
msg.raw = payload;

return msg;

// ============================================================
// 异常检测 v4.0 — PR 性能比 + 数据库注册表 + 30分钟冷却
//
// k 值和设备信息从 global.device_registry 读取（来源：PostgreSQL）
// GHI 从 global.ghi_map 按坐标就近匹配
// ============================================================

const payload = msg.raw;
const device_id = msg.device_id;

// ========== 从数据库注册表获取设备信息 ==========
const registry = global.get('device_registry') || {};
const dev_info = registry[device_id];
const is_real = dev_info !== undefined;

// ========== 获取 GHI 和 k ==========
let ghi, k;

if (is_real) {
    k = dev_info.k || 0.15;
    ghi = getDeviceGHI(device_id, dev_info);
} else {
    k = payload.sim_k || 0.10;
    ghi = payload.sim_ghi || global.get('latest_ghi') || 0;
}

// 低辐照度不做告警判定
if (ghi <= 50) {
    node.status({ fill: 'grey', shape: 'ring', text: `${device_id}: 低辐照跳过 GHI=${ghi}` });
    return null;
}

// ========== 计算 PR ==========
const p_theoretical = k * ghi;
const pr = payload.power / p_theoretical;

// ========== PR 阈值判定 ==========
let alert = null;

if (pr < 0.3) {
    alert = {
        level: 'critical',
        rule: 'PR_SEVERE',
        device_id: device_id,
        message: `严重偏离！PR=${(pr*100).toFixed(1)}% | 实际${payload.power.toFixed(1)}W / 理论${p_theoretical.toFixed(1)}W | GHI=${ghi}`,
        detail: '面板遮挡 / 逆变器故障 / 断路器跳闸 / 线缆断路',
        pr: pr,
        power: payload.power,
        p_theoretical: p_theoretical,
        ghi: ghi,
        timestamp: new Date()
    };
} else if (pr < 0.7) {
    alert = {
        level: 'warning',
        rule: 'PR_LOW',
        device_id: device_id,
        message: `性能偏低 PR=${(pr*100).toFixed(1)}% | 实际${payload.power.toFixed(1)}W / 理论${p_theoretical.toFixed(1)}W | GHI=${ghi}`,
        detail: '积灰 / 部分遮挡 / 逆变器效率下降',
        pr: pr,
        power: payload.power,
        p_theoretical: p_theoretical,
        ghi: ghi,
        timestamp: new Date()
    };
} else if (pr > 1.3) {
    alert = {
        level: 'warning',
        rule: 'PR_HIGH',
        device_id: device_id,
        message: `PR异常偏高 ${(pr*100).toFixed(1)}% | 实际${payload.power.toFixed(1)}W / 理论${p_theoretical.toFixed(1)}W | GHI=${ghi}`,
        detail: '辐照度传感器偏低 / 功率计偏高 / k值需要重新校准',
        pr: pr,
        power: payload.power,
        p_theoretical: p_theoretical,
        ghi: ghi,
        timestamp: new Date()
    };
}

// ========== 冷却限流：同设备同规则，30分钟内只报一次 ==========
if (alert) {
    const cooldown_key = `cd_${device_id}_${alert.rule}`;
    const last_alert = context.get(cooldown_key) || 0;
    const now = Date.now();

    if (now - last_alert < 30 * 60 * 1000) {
        node.status({ fill: 'grey', shape: 'ring', text: `${device_id}: 告警冷却中 (${alert.rule})` });
        return null;
    }
    context.set(cooldown_key, now);

    msg.payload = [
        {
            message: alert.message,
            detail: alert.detail,
            level_code: alert.level === 'critical' ? 3 : 2,
            pr: parseFloat(pr.toFixed(3)),
            power: payload.power,
            p_theoretical: parseFloat(p_theoretical.toFixed(1)),
            ghi: ghi
        },
        {
            device_id: device_id,
            level: alert.level,
            rule: alert.rule
        }
    ];

    const color = alert.level === 'critical' ? 'red' : 'yellow';
    node.status({ fill: color, shape: 'ring', text: `${device_id}: PR=${(pr*100).toFixed(0)}% ${alert.rule}` });
    return msg;
}

node.status({ fill: 'green', shape: 'dot', text: `${device_id}: 正常 PR=${(pr*100).toFixed(0)}%` });
return null;

// ========== 辅助函数 ==========
function getDeviceGHI(dev_id, info) {
    const ghi_map = global.get('ghi_map') || {};

    // 1. 找设备专属 GHI
    if (ghi_map[dev_id]) return ghi_map[dev_id].ghi;

    // 2. 按坐标找最近网格点
    if (info && info.lat && info.lon) {
        let min_dist = Infinity;
        let nearest = 0;
        for (const [id, g] of Object.entries(ghi_map)) {
            const d = (g.lat - info.lat) ** 2 + (g.lon - info.lon) ** 2;
            if (d < min_dist) { min_dist = d; nearest = g.ghi; }
        }
        if (nearest > 0) return nearest;
    }

    // 3. 全局回退
    return global.get('latest_ghi') || 0;
}

// 捕获上游节点的错误信息
const error_info = {
    timestamp: new Date().toISOString(),
    error: msg.error ? msg.error.message : 'Unknown error',
    topic: msg.topic || 'unknown',
    payload: msg.payload || null
};

// 输出到错误日志 debug 节点
msg.payload = error_info;

// 如果有写入错误日志的 InfluxDB 节点
msg.influx_data = {
    measurement: 'error_log',
    tags: { source: 'node-red' },
    fields: {
        error_message: error_info.error,
        topic: error_info.topic
    },
    timestamp: new Date()
};

node.warn(`Error caught: ${error_info.error}`);
return msg;

const registry = global.get('device_registry') || {};
const device_id = msg.device_id;
const deviceInfo = registry[String(device_id)];

if (deviceInfo) {
    msg.payload[1].region    = deviceInfo.location ? deviceInfo.location.toLowerCase() : "unknown";
    msg.payload[1].latitude  = String(deviceInfo.lat);
    msg.payload[1].longitude = String(deviceInfo.lon);
} else if (msg.raw && msg.raw.latitude && msg.raw.longitude) {
    msg.payload[1].latitude  = String(msg.raw.latitude);
    msg.payload[1].longitude = String(msg.raw.longitude);
    msg.payload[1].region    = "simulated";
}

return msg;

// ============================================================
// 全岛批量模拟器 v4.4 — 云层持续性 + 紧贴k线 + 低频故障
// ============================================================

// ========== 从注册表读取模拟设备 ==========
const registry = global.get('device_registry') || {};
const sim_devices = Object.entries(registry)
    .filter(([id, info]) => info.device_type === 'simulated' && info.status === 'active')
    .map(([id, info]) => ({
        id: id,
        lat: info.lat,
        lon: info.lon,
        k: info.k || 0.15,
        orientation_factor: parseFloat((0.93 + Math.random() * 0.05).toFixed(3))
    }));

if (sim_devices.length === 0) {
    node.status({ fill: 'red', shape: 'ring', text: 'No simulated devices in registry' });
    return null;
}

// ========== 故障状态机 ==========
let fault_states = flow.get('sim_fault_states') || {};
const now = Date.now();

for (const dev of sim_devices) {
    if (!fault_states[dev.id]) {
        fault_states[dev.id] = { state: 'normal', start: 0, duration: 0 };
    }
    const fs = fault_states[dev.id];
    if (fs.state !== 'normal' && now > fs.start + fs.duration) {
        fs.state = 'normal';
        fs.start = 0;
        fs.duration = 0;
    }
}

// ========== 云层持续性状态机 ==========
let cloud_states = flow.get('sim_cloud_states') || {};
for (const dev of sim_devices) {
    if (!cloud_states[dev.id] || now > (cloud_states[dev.id].until || 0)) {
        const r = Math.random();
        let cloud, duration;
        if (r < 0.03) {
            cloud = 0.45 + Math.random() * 0.15;
            duration = (30 + Math.random() * 30) * 60 * 1000;
        } else if (r < 0.15) {
            cloud = 0.72 + Math.random() * 0.13;
            duration = (20 + Math.random() * 20) * 60 * 1000;
        } else {
            cloud = 0.95 + Math.random() * 0.05;
            duration = (60 + Math.random() * 120) * 60 * 1000;
        }
        cloud_states[dev.id] = { factor: cloud, until: now + duration };
    }
}
flow.set('sim_cloud_states', cloud_states);

// ========== GHI 相关 ==========
const base_ghi = global.get('latest_ghi') || 0;
const air_temp = global.get('latest_air_temp') || 25;
const is_night = base_ghi < 10;
const ghi_map = global.get('ghi_map') || {};

function getNearestGHI(lat, lon) {
    let min_dist = Infinity;
    let nearest_ghi = base_ghi;
    for (const [id, info] of Object.entries(ghi_map)) {
        const dlat = info.lat - lat;
        const dlon = info.lon - lon;
        const dist = dlat * dlat + dlon * dlon;
        if (dist < min_dist) {
            min_dist = dist;
            nearest_ghi = info.ghi || 0;
        }
    }
    return nearest_ghi;
}

// ========== 远程控制状态 ==========
const manual_off = global.get('manual_off_devices') || {};

// ========== 触发故障（每类每天约1台） ==========
let fault_count = 0;
let manual_off_count = 0;

for (const dev of sim_devices) {
    const fs = fault_states[dev.id];
    if (!is_night && fs.state === 'normal') {
        const rand = Math.random();
        if (rand < 0.0000333) {
            // 逆变器故障：50台中约每天1台，持续20~30分钟
            fs.state = 'inverter_fault';
            fs.start = now;
            fs.duration = (20 + Math.random() * 10) * 60 * 1000;
        } else if (rand < 0.0000667) {
            // 灰尘积累：50台中约每天1台，持续30~40分钟
            fs.state = 'dusty';
            fs.start = now;
            fs.duration = (30 + Math.random() * 10) * 60 * 1000;
        } else if (rand < 0.0001) {
            // 遮挡：50台中约每天1台，持续20~30分钟
            fs.state = 'shaded';
            fs.start = now;
            fs.duration = (20 + Math.random() * 10) * 60 * 1000;
        }
    }
}

flow.set('sim_fault_states', fault_states);

// ========== 生成数据 ==========
let messages = [];

for (const dev of sim_devices) {
    const fs = fault_states[dev.id];
    let local_ghi, pr, fault_type, power;

    // GHI + 微波动 ±3%
    const raw_ghi = getNearestGHI(dev.lat, dev.lon);
    const device_base_ghi = raw_ghi * (0.97 + Math.random() * 0.06);

    const is_manual_off = manual_off[dev.id] === true;

    if (is_manual_off) {
        local_ghi = is_night ? 0 : device_base_ghi * 0.95;
        pr = 0; power = 0; fault_type = 'manual_off';
        manual_off_count++;
    } else if (is_night) {
        local_ghi = 0; pr = 0; power = 0; fault_type = 'normal';
    } else {
        // 云层持续性 + 微波动 ±1.5%
        local_ghi = device_base_ghi * cloud_states[dev.id].factor * (0.985 + Math.random() * 0.03);

        switch (fs.state) {
            case 'inverter_fault':
                pr = 0.05 + Math.random() * 0.15; fault_type = 'severe'; fault_count++; break;
            case 'dusty':
                pr = 0.55 + Math.random() * 0.15; fault_type = 'degraded'; break;
            case 'shaded':
                pr = 0.20 + Math.random() * 0.25; fault_type = 'severe'; fault_count++; break;
            default:
                pr = 0.90 + Math.random() * 0.06; fault_type = 'normal';
        }
        const p_theoretical = dev.k * local_ghi * dev.orientation_factor;
        power = Math.max(0, p_theoretical * pr);
    }

    const voltage = is_manual_off ? 0 : (230 + (Math.random() * 4 - 2));
    const current = (is_night || is_manual_off) ? 0 : power / voltage;
    const temperature = air_temp + (is_night ? 5 : 15) + Math.random() * 10;

    messages.push({
        payload: {
            device_id: dev.id,
            timestamp: Math.floor(Date.now() / 1000),
            voltage: parseFloat(voltage.toFixed(1)),
            current: parseFloat(current.toFixed(2)),
            power: parseFloat(power.toFixed(1)),
            status: !is_manual_off && fs.state !== 'inverter_fault',
            efficiency: parseFloat(pr.toFixed(2)),
            temperature: parseFloat(temperature.toFixed(1)),
            latitude: dev.lat,
            longitude: dev.lon,
            sim_ghi: parseFloat((local_ghi || 0).toFixed(1)),
            sim_k: dev.k,
            sim_pr: parseFloat(pr.toFixed(3)),
            sim_fault: fault_type
        },
        topic: `pv/${dev.id}/data`
    });
}

// ========== 状态显示 ==========
const ghi_points = Object.keys(ghi_map).length;
const states = sim_devices.reduce((acc, d) => {
    if (manual_off[d.id]) {
        acc['manual_off'] = (acc['manual_off'] || 0) + 1;
    } else {
        acc[fault_states[d.id].state] = (acc[fault_states[d.id].state] || 0) + 1;
    }
    return acc;
}, {});
const status_text = Object.entries(states).map(([k, v]) => `${k}:${v}`).join(' | ');

node.status({
    fill: (fault_count > 0 || manual_off_count > 0) ? 'red' : (is_night ? 'grey' : 'green'),
    shape: 'dot',
    text: `${is_night ? '🌙' : '☀'} ${sim_devices.length}台 | ${status_text} | GHI点:${ghi_points} | ${new Date().toLocaleTimeString()}`
});

return [messages];

// ============================================================
// 合并辐照度+功率 v4.0 — 每设备独立 GHI（按坐标就近匹配）
//
// 真实设备 → 从 ghi_map 找该设备精确坐标的 GHI
// 模拟设备 → 用 sim_ghi（模拟器已按就近网格点生成）
// 回退     → 如果都找不到，用 latest_ghi
// ============================================================

const fields = msg.payload[0];
const tags = msg.payload[1];

const power = fields.power || 0;
const device_id = tags.device_id || 'unknown';

// ========== 从数据库注册表获取设备信息 ==========
const registry = global.get('device_registry') || {};
const dev_info = registry[device_id];
const is_real = dev_info !== undefined;

// ========== 获取该设备的 GHI ==========
const ghi_map = global.get('ghi_map') || {};
let ghi, air_temp, data_source, k;

if (is_real) {
    // 真实设备：从数据库获取 k 值
    k = dev_info.k || 0.15;
    data_source = 'api';

    // GHI 优先级：设备专属 > 就近网格点 > 全局回退
    if (ghi_map[device_id]) {
        ghi = ghi_map[device_id].ghi;
        air_temp = ghi_map[device_id].temp;
    } else {
        ghi = findNearestGHI(ghi_map, dev_info.lat, dev_info.lon);
        air_temp = global.get('latest_air_temp') || 0;
    }
} else {
    // 模拟设备：用模拟器自带的 sim_ghi 和 sim_k
    k = fields.sim_k || 0.15;
    data_source = 'simulator';

    if (fields.sim_ghi !== undefined) {
        ghi = fields.sim_ghi;
    } else if (fields.latitude && fields.longitude) {
        ghi = findNearestGHI(ghi_map, fields.latitude, fields.longitude);
    } else {
        ghi = global.get('latest_ghi') || 0;
    }
    air_temp = global.get('latest_air_temp') || 0;
}

// ========== 计算 PR ==========
const low_irradiance = ghi <= 50;
const p_theoretical = k * ghi;
let pr_value = -1;
let fault_flag = 0;

if (!low_irradiance && p_theoretical > 0) {
    pr_value = parseFloat((power / p_theoretical).toFixed(3));
    if (pr_value < 0.3) fault_flag = 3;
    else if (pr_value < 0.7) fault_flag = 2;
    else if (pr_value > 1.3) fault_flag = 1;
}

// ========== 写入 InfluxDB ==========
// 获取坐标
let lat, lon;
if (is_real && dev_info) {
    lat = dev_info.lat;
    lon = dev_info.lon;
} else {
    lat = fields.latitude || 0;
    lon = fields.longitude || 0;
}

msg.payload = [
    {
        ghi: ghi,
        power: power,
        p_theoretical: parseFloat(p_theoretical.toFixed(1)),
        performance_ratio: pr_value,
        fault_flag: fault_flag,
        k_factor: k,
        air_temp: air_temp,
        latitude: lat,
        longitude: lon
    },
    {
        device_id: device_id,
        location: is_real ? (dev_info.location || "Cyprus") : (tags.location || "Cyprus"),
        data_source: data_source,
        device_type: is_real ? "real" : "simulated"
    }
];

// ========== 状态显示 ==========
const color = low_irradiance ? 'grey' : (fault_flag >= 2 ? 'red' : 'green');
const pr_text = low_irradiance ? '夜间' : (pr_value * 100).toFixed(1) + '%';
const prefix = is_real ? '📡' : '🤖';
node.status({
    fill: color, shape: 'dot',
    text: `${prefix} ${device_id} | GHI=${ghi} | P=${power}W | PR=${pr_text}`
});

return msg;

// ========== 辅助函数：按坐标找最近网格点的 GHI ==========
function findNearestGHI(map, lat, lon) {
    let min_dist = Infinity;
    let nearest_ghi = global.get('latest_ghi') || 0;

    for (const [id, info] of Object.entries(map)) {
        const dlat = info.lat - lat;
        const dlon = info.lon - lon;
        const dist = dlat * dlat + dlon * dlon;
        if (dist < min_dist) {
            min_dist = dist;
            nearest_ghi = info.ghi;
        }
    }
    return nearest_ghi;
}

flow.set('sim_fault_states', {});
flow.set('sim_cloud_states', {});
msg.payload = "All states cleared";
return msg;

// ============================================================
// Open-Meteo URL 构建 v3.0 — 从 PostgreSQL 注册表读取坐标
//
// 读取 global.irradiance_points（由设备注册表同步流程维护）
// 为每个坐标点发一个 HTTP 请求获取 GHI
// ============================================================

const points = global.get('irradiance_points') || [];

if (points.length === 0) {
    node.status({ fill: 'red', shape: 'ring', text: '无采集点，等待注册表同步...' });
    node.warn('irradiance_points 为空，请检查设备注册表同步流程');
    return null;
}

const BASE = 'https://api.open-meteo.com/v1/forecast';

for (const point of points) {
    const url = `${BASE}?latitude=${point.lat}&longitude=${point.lon}`
        + `&current=shortwave_radiation,temperature_2m,cloud_cover`
        + `&timezone=auto`;

    node.send({
        url: url,
        point_id: point.id,
        point_lat: point.lat,
        point_lon: point.lon,
        point_name: point.id
    });
}

node.status({
    fill: 'blue', shape: 'dot',
    text: `已请求 ${points.length} 个坐标 | ${new Date().toLocaleTimeString()}`
});
return null;

// ============================================================
// Transform v2.0 — 存储每个坐标点的独立 GHI
//
// 输入：Open-Meteo 单坐标响应
// 输出：
//   1. 更新 global.ghi_map（供主管道使用）
//   2. 写入 InfluxDB（供 Grafana 显示）
//
// global.ghi_map 结构：
//   {
//     'nicosia':    { ghi: 500, temp: 25, cloud: 10, lat: 35.18, lon: 33.38 },
//     'device_001': { ghi: 515, temp: 26, cloud: 8,  lat: 34.67, lon: 33.04 },
//     ...
//   }
// ============================================================

const data = msg.payload;
const point_id = msg.point_id;
const point_lat = msg.point_lat;
const point_lon = msg.point_lon;
const point_name = msg.point_name;

if (!data || !data.current) {
    node.warn(`Open-Meteo: 无数据 (${point_id})`);
    return null;
}

const ghi = data.current.shortwave_radiation || 0;
const temp = data.current.temperature_2m || 0;
const cloud = data.current.cloud_cover || 0;

// ========== 1. 存入 global ghi_map ==========
let ghi_map = global.get('ghi_map') || {};
ghi_map[point_id] = {
    ghi: ghi,
    temp: temp,
    cloud: cloud,
    lat: point_lat,
    lon: point_lon,
    name: point_name,
    updated: new Date().toISOString()
};
global.set('ghi_map', ghi_map);

// 兼容旧代码：保持 latest_ghi（用第一个尼科西亚或任意点）
if (point_id === 'nicosia') {
    global.set('latest_ghi', ghi);
    global.set('latest_air_temp', temp);
}
// 如果还没设过 latest_ghi，用当前点
if (!global.get('latest_ghi') && ghi > 0) {
    global.set('latest_ghi', ghi);
    global.set('latest_air_temp', temp);
}

// ========== 2. 写入 InfluxDB ==========
msg.payload = [
    {
        ghi: ghi,
        ambient_temp: temp,
        cloud_cover: cloud,
        latitude: point_lat,
        longitude: point_lon
    },
    {
        source: 'open-meteo',
        data_type: 'actual',
        location: point_name,
        point_id: point_id
    }
];

node.status({ fill: 'green', shape: 'dot', text: `${point_name}: GHI=${ghi} | ${temp}°C` });
return msg;

// ============================================================
// 远程控制指令构建 v2.0
// 新增：同步更新模拟器设备状态（flow context）
// ============================================================

// dropdown 选择设备
if (msg.topic === 'select_device') {
    flow.set('selected_device', msg.payload);
    node.status({ fill: 'blue', shape: 'dot', text: `已选择: ${msg.payload}` });
    return null;
}

// switch 触发控制
if (msg.topic === 'breaker_control') {
    const device_id = flow.get('selected_device');
    if (!device_id) {
        node.status({ fill: 'red', shape: 'ring', text: '请先选择设备！' });
        node.warn('未选择设备');
        return null;
    }

    const command = msg.payload;  // "on" 或 "off"
    const action = command === 'on' ? '合闸' : '分闸';
    const now_str = new Date().toLocaleTimeString();

    // ========== 同步更新模拟器的设备状态 ==========
    const manual_off = global.get('manual_off_devices') || {};
    if (command === 'off') {
        manual_off[device_id] = true;
    } else {
        delete manual_off[device_id];
    }
    global.set('manual_off_devices', manual_off);

    // 构建 MQTT 消息
    const mqtt_msg = {
        topic: `pv/${device_id}/control`,
        payload: JSON.stringify({
            command: command,
            device_id: device_id,
            timestamp: Math.floor(Date.now() / 1000),
            source: "dashboard"
        })
    };

    // 构建状态反馈
    const status_msg = {
        payload: `${now_str} | ${device_id} → ${action}`
    };

    // 构建控制日志
    const log_msg = {
        payload: [
            {
                command_str: action,
                command_code: command === 'on' ? 1.0 : 0.0,
                source: "dashboard"
            },
            {
                device_id: device_id,
                action: command
            }
        ]
    };

    node.status({
        fill: command === 'on' ? 'green' : 'red',
        shape: 'dot',
        text: `${device_id}: ${action} | ${now_str}`
    });

    return [mqtt_msg, status_msg, log_msg, mqtt_msg];
}

return null;

// ============================================================
// 设备注册表同步 — PostgreSQL → global context
//
// 输出：
//   global.device_registry = {
//     'device_001': { lat, lon, k, name, location, ... },
//     'device_002': { lat, lon, k, name, location, ... },
//   }
//
//   global.irradiance_points = [
//     { id: 'nicosia',    lat: 35.1856, lon: 33.3823 },
//     { id: 'device_001', lat: 34.6757, lon: 33.0424 },
//     ...
//   ]
// ============================================================

const rows = msg.payload;

if (!rows || !Array.isArray(rows) || rows.length === 0) {
    node.status({ fill: 'yellow', shape: 'ring', text: '数据库无设备记录' });
    node.warn('device_registry 表为空');
    return null;
}

// ========== 1. 构建设备注册表 ==========
const registry = {};
for (const row of rows) {
    registry[row.device_id] = {
        lat: row.latitude,
        lon: row.longitude,
        k: row.k_factor || 0.15,
        name: row.name || row.device_id,
        location: row.location || 'Cyprus',
        panel_power: row.panel_power_wp || 0,
        device_type: row.device_type || 'real',
        status: row.status || 'active'
    };
}
global.set('device_registry', registry);

// ========== 2. 构建辐照度采集点列表 ==========
// 塞浦路斯基础网格点（保证全岛覆盖）
const GRID_POINTS = [
    { id: 'nicosia',   lat: 35.1856, lon: 33.3823 },
    { id: 'limassol',  lat: 34.6841, lon: 33.0379 },
    { id: 'larnaca',   lat: 34.9229, lon: 33.6233 },
    { id: 'paphos',    lat: 34.7720, lon: 32.4297 },
    { id: 'famagusta', lat: 35.1174, lon: 33.9418 },
    { id: 'troodos',   lat: 34.9267, lon: 32.8800 },
    { id: 'polis',     lat: 35.0355, lon: 32.4264 },
    { id: 'protaras',  lat: 35.0125, lon: 34.0583 },
];

const all_points = [...GRID_POINTS];

// 把每台真实设备的坐标加入采集列表（去重：距已有点 < 5km 则跳过）
for (const [dev_id, info] of Object.entries(registry)) {
    const too_close = all_points.some(p =>
        Math.abs(p.lat - info.lat) < 0.05 && Math.abs(p.lon - info.lon) < 0.05
    );
    if (!too_close) {
        all_points.push({ id: dev_id, lat: info.lat, lon: info.lon });
    }
}

global.set('irradiance_points', all_points);

// ========== 3. 日志 ==========
const device_list = Object.keys(registry).join(', ');
node.status({
    fill: 'green', shape: 'dot',
    text: `${rows.length} 台设备 | ${all_points.length} 个采集点 | ${new Date().toLocaleTimeString()}`
});

node.warn(`注册表同步完成: ${rows.length} 台设备 [${device_list}], ${all_points.length} 个辐照度采集点`);

return msg;

const registry = global.get('device_registry') || {};
msg.payload = {
    registry_keys: Object.keys(registry),
    device_001: registry['device_001'],
    full_registry: registry
};
return msg;
